// http://gyaki.org/index.html

var app, browserHeight, browserWidth, initCallbacks, initElements, initParams, resize, updateSelection;

app = {};

$(function() {
  initElements();
  initParams();
  initCallbacks();
  return resize();
});

browserWidth = function() {
  if (window.innerWidth) {
    return window.innerWidth;
  }
  if (document.body) {
    return document.body.clientWidth;
  }
  return 0;
};

browserHeight = function() {
  if (window.innerHeight) {
    return window.innerHeight;
  }
  if (document.body) {
    return document.body.clientHeight;
  }
  return 0;
};

resize = function() {
  var buttonHeight, buttonWidth, canvasSize, gap, i, img, j, k, orientation, results, results1;
  window.devicePixelRatio = 1.0;
  app.width = browserWidth();
  app.height = browserHeight();
  canvasSize = app.height < app.width ? app.height : app.width;
  if (gyazoImageID) {
    // http://paulownia.hatenablog.com/entry/20100602/1275493299
    // Gyazo.comから画像を取得するとクロスドメインでエラーになるので
    // Gyaki.com/gyazodataから間接的に画像を取得する
    img = new Image();
    img.src = `/gyazodata/${gyazoImageID}`;
    img.onload = function() {
      return app.context.drawImage(img, 0, 0);
    };
  }
  
  //if window.orientation
  //  alert "window.orientation = #{window.orientation}"
  //  # タブレットのブラウザではwindow.orientationという値に
  //  # -90, 0, 90, 180 などの値が入る
  //  if window.orientation == '0' || window.orientation == '180'
  //    'portrait'
  //  else
  //    [app.width, app.height] = [app.height, app.width]
  //    'landscape'
  //else
  //  if app.width > app.height
  //    'landscape'
  //  else
  //    'portrait'
  orientation = app.width > app.height ? 'landscape' : 'portrait';
  app.canvas.attr('width', canvasSize).attr('height', canvasSize);
  app.context.fillStyle = '#fff';
  app.context.fillRect(0, 0, app.width, app.height);
  if (orientation === 'portrait') {
    buttonWidth = app.width / 10;
    buttonHeight = buttonWidth;
    gap = (app.width - (buttonWidth * 7)) / 11;
    app.uploadButton.css('top', app.width + gap).css('left', gap).css('width', buttonWidth).css('height', buttonHeight).css('visibility', 'visible');
    results = [];
    for (i = j = 0; j < 3; i = ++j) {
      app.lineButtons[i].css('top', app.width + gap).css('left', gap * 3 + buttonWidth + (buttonWidth + gap) * i).css('width', buttonWidth).css('height', buttonWidth).css('visibility', 'visible');
      results.push(app.colorButtons[i].css('top', app.width + gap).css('left', gap * 7 + buttonWidth * 4 + (buttonWidth + gap) * i).css('width', buttonWidth).css('height', buttonWidth).css('visibility', 'visible')); // landscape
    }
    return results;
  } else {
    buttonHeight = app.height / 10;
    buttonWidth = buttonHeight;
    gap = (app.height - (buttonHeight * 7)) / 11;
    app.uploadButton.css('top', gap).css('left', canvasSize + gap).css('width', buttonWidth).css('height', buttonHeight).css('visibility', 'visible');
    results1 = [];
    for (i = k = 0; k < 3; i = ++k) {
      app.lineButtons[i].css('top', gap * 3 + buttonWidth + (buttonWidth + gap) * i).css('left', canvasSize + gap).css('width', buttonWidth).css('height', buttonHeight).css('visibility', 'visible');
      results1.push(app.colorButtons[i].css('top', gap * 7 + buttonWidth * 4 + (buttonWidth + gap) * i).css('left', canvasSize + gap).css('width', buttonWidth).css('height', buttonHeight).css('visibility', 'visible'));
    }
    return results1;
  }
};

initElements = function() {
  var button, i, j, k, len, len1, ref, ref1, results;
  app.canvas = $('<canvas>');
  $('body').append(app.canvas);
  app.uploadButton = $('<input type="button">').css('position', 'absolute').css('visibility', 'hidden').attr('value', 'UP');
  $('body').append(app.uploadButton);
  app.lineButtons = (function() {
    var j, results;
    results = [];
    for (i = j = 0; j < 3; i = ++j) {
      results.push($('<img>').css('position', 'absolute').css('visibility', 'hidden').attr('src', `/images/line${i + 1}.png`));
    }
    return results;
  })();
  ref = app.lineButtons;
  for (j = 0, len = ref.length; j < len; j++) {
    button = ref[j];
    $('body').append(button);
  }
  app.colorButtons = (function() {
    var k, results;
    results = [];
    for (i = k = 0; k <= 3; i = ++k) {
      results.push($('<img>').css('position', 'absolute').css('visibility', 'hidden').attr('src', `images/color${i + 1}.png`));
    }
    return results;
  })();
  ref1 = app.colorButtons;
  results = [];
  for (k = 0, len1 = ref1.length; k < len1; k++) {
    button = ref1[k];
    results.push($('body').append(button));
  }
  return results;
};

updateSelection = function() {
  var colors, i, j, k, lineWidths, results;
  lineWidths = [3, 15, 30];
  for (i = j = 0; j < 3; i = ++j) {
    if (lineWidths[i] === app.lineWidth) {
      app.lineButtons[i].css('background-color', 'rgba(0, 0, 0, 0.15)').css('border-radius', '6px').css('border', 'none');
    } else {
      app.lineButtons[i].css('background-color', 'transparent').css('border-radius', '6px').css('border', 'none');
    }
  }
  colors = ['rgb(255, 255, 255)', 'rgb(128, 128, 128)', 'rgb(0, 0, 0)'];
  results = [];
  for (i = k = 0; k < 3; i = ++k) {
    if (colors[i] === app.strokeStyle) {
      results.push(app.colorButtons[i].css('background-color', 'rgba(0, 0, 0, 0.15)').css('border-radius', '6px').css('border', 'none'));
    } else {
      results.push(app.colorButtons[i].css('background-color', 'transparent').css('border-radius', '6px').css('border', 'none'));
    }
  }
  return results;
};

initParams = function() {
  window.devicePixelRatio = 1.0;
  app.canvasX = app.canvas.offset()["left"];
  app.canvasY = app.canvas.offset()["top"];
  app.crd = {
    cur: [0, 0],
    pre: [0, 0]
  };
  app.drawing = false;
  app.lineWidth = 15;
  app.strokeStyle = 'rgb(0, 0, 0)';
  app.context = app.canvas[0].getContext('2d'); // jQueryは配列になってるらしいのでこういう細工が必要
  app.lineButtons[0].on('click', function(e) {
    app.lineWidth = 3;
    return updateSelection();
  });
  app.lineButtons[1].on('click', function(e) {
    app.lineWidth = 15;
    return updateSelection();
  });
  app.lineButtons[2].on('click', function(e) {
    app.lineWidth = 30;
    return updateSelection();
  });
  app.colorButtons[0].on('click', function(e) {
    app.strokeStyle = 'rgb(255, 255, 255)';
    return updateSelection();
  });
  app.colorButtons[1].on('click', function(e) {
    app.strokeStyle = 'rgb(128, 128, 128)';
    return updateSelection();
  });
  app.colorButtons[2].on('click', function(e) {
    app.strokeStyle = 'rgb(0, 0, 0)';
    return updateSelection();
  });
  return updateSelection();
};

initCallbacks = function() {
  app.canvas.on('touchmove mousemove', function(e) {
    var x, y;
    e.preventDefault();
    [x, y] = 'touchmove' === e.type ? [e.originalEvent.changedTouches[0].pageX, e.originalEvent.changedTouches[0].pageY] : [e.pageX, e.pageY];
    [x, y] = [x - app.canvasX, y - app.canvasY];
    if (x === app.width / 2 && y === app.width / 2) { // GalaxyNexusのバグ? 回避
      return;
    }
    if (app.drawing) {
      // preからcurまで線を引く
      // 線の属性はこのように毎回セットしないとうまく描けなかったりする...

      // 何故かNexus6でうまく動かない。stroke()するたびに全部クリアしてしまう。
      // 解決方法は不明。(2015/02/08 20:01:47)

      app.crd.cur = [x, y];
      app.context.beginPath();
      app.context.lineJoin = "round";
      app.context.lineCap = "round";
      app.context.strokeStyle = app.strokeStyle;
      app.context.lineWidth = app.lineWidth;
      app.context.moveTo(app.crd.pre[0], app.crd.pre[1]);
      app.context.lineTo(app.crd.cur[0], app.crd.cur[1]);
      app.context.stroke();
      app.context.closePath();
      return app.crd.pre = app.crd.cur;
    }
  });
  app.canvas.on('touchstart mousedown', function(e) {
    var x, y;
    e.preventDefault();
    [x, y] = 'touchstart' === e.type ? [e.originalEvent.changedTouches[0].pageX, e.originalEvent.changedTouches[0].pageY] : [e.pageX, e.pageY];
    app.crd.pre = [x - app.canvasX, y - app.canvasY];
    return app.drawing = true;
  });
  app.canvas.on('touchend mouseup', function(e) {
    e.preventDefault();
    return app.drawing = false;
  });
  return app.uploadButton.on('click', function(e) {
    var imagedata;
    imagedata = app.canvas[0].toDataURL();
    return $.ajax({
      type: 'POST',
      url: '/upload',
      data: {
        data: imagedata,
        id: gyazoUserID
      },
      success: function(data, textStatus, jqXHR) {
        return location.href = data; // Gyazoページに移動
      }
    });
  });
};


